import { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import "./EmployeeForm.css";

function AddEmployee() {

  const navigate = useNavigate();
  const { id } = useParams();
  const isEditMode = Boolean(id);

  const [activeTab,setActiveTab] = useState("personal");

  const [employee,setEmployee] = useState({
    firstName:"",
    lastName:"",
    empId:"",
    gender:"",
    dob:"",
    maritalStatus:"",
    email:"",
    aadhar:"",
    pan:"",
    designation:"",
    department:"",
    salary:"",
    role:"",
    skills:[],
    tempSkill:"",
    customSkill:"",
    bankName:"",
    accountNumber:"",
    ifsc:"",
    qualification:"",
    university:"",
    passingYear:"",
    employeeFiles:[],
    certificates:[]
  });

  const skillOptions=[
    "C","C++","Java","Advanced Java","Python",
    "NodeJS","React","Angular","MongoDB"
  ];

  const [designations,setDesignations]=useState([]);

  useEffect(()=>{
    const saved=JSON.parse(localStorage.getItem("designations"))||[];
    setDesignations(saved);
  },[]);

  /* SAFE EDIT LOAD */
  useEffect(()=>{
    if(!isEditMode) return;

    const employees=JSON.parse(localStorage.getItem("employees"))||[];
    const found=employees.find(e=>String(e.id)===String(id));

    if(found){
      setEmployee(prev=>({
        ...prev,
        ...found,
        employeeFiles:found.employeeFiles||[],
        certificates:found.certificates||[],
        skills:found.skills||[]
      }));
    }
  },[id,isEditMode]);

  /* VALIDATION */
  const validateAadhar=(v)=>/^\d{12}$/.test(v);
  const validatePAN=(v)=>/^[A-Z]{5}[0-9]{4}[A-Z]{1}$/.test(v);

  /* INPUT */
  const handleChange=(e)=>{
    const {name,value}=e.target;

    if(name==="pan"){
      setEmployee({...employee,pan:value.toUpperCase()});
      return;
    }

    setEmployee({...employee,[name]:value});
  };

  /* FILE HANDLING */
  const convertFiles=(files)=>(
    files.map(file=>({
      name:file.name,
      size:file.size,
      type:file.type,
      data:URL.createObjectURL(file)
    }))
  );

  const handleFileUpload=(files,field)=>{
    const converted=convertFiles(Array.from(files));
    setEmployee(prev=>({
      ...prev,
      [field]:[...(prev[field]||[]),...converted]
    }));
  };

  const removeFile=(i,field)=>{
    const arr=[...(employee[field]||[])];
    arr.splice(i,1);
    setEmployee({...employee,[field]:arr});
  };

  const FileCards=(field)=>{
    const files=employee[field]||[];
    return (
      <div className="file-card-container">
        {files.map((f,i)=>(
          <div key={i} className="file-card">
            <span>{f.name}</span>
            <button type="button" onClick={()=>removeFile(i,field)}>✖</button>
          </div>
        ))}
      </div>
    );
  };

  const DropZone=({field})=>(
    <div
      className="dropzone"
      onDragOver={(e)=>e.preventDefault()}
      onDrop={(e)=>{
        e.preventDefault();
        handleFileUpload(e.dataTransfer.files,field);
      }}
    >
      Drag files here or
      <input type="file" multiple onChange={(e)=>handleFileUpload(e.target.files,field)} />
      {FileCards(field)}
    </div>
  );

  /* SKILLS */
  const addSkill=()=>{
    let newSkill="";

    if(employee.tempSkill==="Other"){
      if(!employee.customSkill.trim()) return;
      newSkill=employee.customSkill.trim();
    }else{
      if(!employee.tempSkill) return;
      newSkill=employee.tempSkill;
    }

    if(!employee.skills.includes(newSkill)){
      setEmployee(prev=>({
        ...prev,
        skills:[...prev.skills,newSkill],
        tempSkill:"",
        customSkill:""
      }));
    }
  };

  const removeSkill=(skill)=>{
    setEmployee(prev=>({
      ...prev,
      skills:prev.skills.filter(s=>s!==skill)
    }));
  };

  /* SAVE */
  const handleSubmit=(e)=>{
    e.preventDefault();

    if(!validateAadhar(employee.aadhar)){
      alert("Invalid Aadhar (12 digits)");
      return;
    }

    if(!validatePAN(employee.pan)){
      alert("Invalid PAN format");
      return;
    }

    let employees=JSON.parse(localStorage.getItem("employees"))||[];

    if(isEditMode){
      employees=employees.map(emp =>
        String(emp.id)===String(id)
          ? {...emp,...employee}
          : emp
      );
    }else{
      employees.push({
        id:Date.now(),
        name:`${employee.firstName} ${employee.lastName}`,
        ...employee
      });
    }

    localStorage.setItem("employees",JSON.stringify(employees));
    alert("Saved Successfully");
    navigate("/dashboard/employee-details");
  };

  /* ================= UI ================= */

  const Field=(label,element)=>(
    <div className="form-field">
      <label>{label}</label>
      {element}
    </div>
  );

  return (
    <div className="add-employee-page">

      <h2>{isEditMode?"Edit Employee":"Add Employee"}</h2>

      <div className="tabs">
        {["personal","employment","bank","education"].map(t=>(
          <button key={t}
            className={`tab ${activeTab===t?"active":""}`}
            onClick={()=>setActiveTab(t)}>
            {t.toUpperCase()}
          </button>
        ))}
      </div>

      <form className="employee-form" onSubmit={handleSubmit}>

        {/* PERSONAL */}
        {activeTab==="personal" && (
          <>
            <h3>Personal Details</h3>
            <div className="employee-grid">

              {Field("First Name",
                <input name="firstName" value={employee.firstName} onChange={handleChange}/>
              )}

              {Field("Last Name",
                <input name="lastName" value={employee.lastName} onChange={handleChange}/>
              )}

              {Field("Employee ID",
                <input name="empId" value={employee.empId} onChange={handleChange}/>
              )}

              {Field("Gender",
                <select name="gender" value={employee.gender} onChange={handleChange}>
                  <option value="">Select</option>
                  <option>Male</option>
                  <option>Female</option>
                </select>
              )}

              {Field("Date of Birth",
                <input type="date" name="dob" value={employee.dob} onChange={handleChange}/>
              )}

              {Field("Marital Status",
                <select name="maritalStatus" value={employee.maritalStatus} onChange={handleChange}>
                  <option value="">Select</option>
                  <option>Single</option>
                  <option>Married</option>
                </select>
              )}

              {Field("Email",
                <input type="email" name="email" value={employee.email} onChange={handleChange}/>
              )}

              {Field("Aadhar Number",
                <input name="aadhar" maxLength="12" value={employee.aadhar} onChange={handleChange}/>
              )}

              {Field("PAN Number",
                <input name="pan" maxLength="10" value={employee.pan} onChange={handleChange}/>
              )}

              <div style={{gridColumn:"1/span 2"}}>
                <label>Upload Employee Documents</label>
                <DropZone field="employeeFiles"/>
              </div>

            </div>
          </>
        )}

        {/* EMPLOYMENT */}
        {activeTab==="employment" && (
          <>
            <h3>Employment Details</h3>
            <div className="employee-grid">

              {Field("Designation",
                <select name="designation" value={employee.designation} onChange={handleChange}>
                  <option value="">Select</option>
                  {designations.map(d=><option key={d.id}>{d.title}</option>)}
                </select>
              )}

              {Field("Salary",
                <input name="salary" value={employee.salary} onChange={handleChange}/>
              )}

              {Field("Department",
                <select name="department" value={employee.department} onChange={handleChange}>
                  <option value="">Select</option>
                  <option>Frontend</option>
                  <option>Backend</option>
                  <option>IT</option>
                  <option>HR</option>
                </select>
              )}

              {Field("Role",
                <select name="role" value={employee.role} onChange={handleChange}>
                  <option value="">Select</option>
                  <option>Employee</option>
                  <option>Admin</option>
                </select>
              )}

              {Field("Skill",
                <select name="tempSkill" value={employee.tempSkill} onChange={handleChange}>
                  <option value="">Select</option>
                  {skillOptions.map(s=><option key={s}>{s}</option>)}
                  <option>Other</option>
                </select>
              )}

              {employee.tempSkill==="Other" &&
                Field("Custom Skill",
                  <input name="customSkill" value={employee.customSkill} onChange={handleChange}/>
                )
              }

              <button type="button" className="save-btn" onClick={addSkill}>
                Add Skill
              </button>

              <div style={{gridColumn:"1/span 2"}}>
                {employee.skills.map(skill=>(
                  <span key={skill} onClick={()=>removeSkill(skill)} className="skill-chip">
                    {skill} ✖
                  </span>
                ))}
              </div>

            </div>
          </>
        )}

        {/* BANK */}
        {activeTab==="bank" && (
          <>
            <h3>Bank Details</h3>
            <div className="employee-grid">
              {Field("Bank Name",
                <input name="bankName" value={employee.bankName} onChange={handleChange}/>
              )}
              {Field("Account Number",
                <input name="accountNumber" value={employee.accountNumber} onChange={handleChange}/>
              )}
              {Field("IFSC Code",
                <input name="ifsc" value={employee.ifsc} onChange={handleChange}/>
              )}
            </div>
          </>
        )}

        {/* EDUCATION */}
        {activeTab==="education" && (
          <>
            <h3>Education Details</h3>
            <div className="employee-grid">

              {Field("Qualification",
                <select name="qualification" value={employee.qualification} onChange={handleChange}>
                  <option value="">Select</option>
                  <option>B.Tech</option>
                  <option>M.Tech</option>
                  <option>MBA</option>
                </select>
              )}

              {Field("University",
                <input name="university" value={employee.university} onChange={handleChange}/>
              )}

              {Field("Passing Year",
                <input name="passingYear" value={employee.passingYear} onChange={handleChange}/>
              )}

              <div style={{gridColumn:"1/span 2"}}>
                <label>Upload Certificates</label>
                <DropZone field="certificates"/>
              </div>

            </div>
          </>
        )}

        <button className="save-btn" type="submit">
          {isEditMode?"Update Employee":"Save Employee"}
        </button>

      </form>
    </div>
  );
}

export default AddEmployee;
